parameters.functionCode:
// Parse AI response and structure knowledge base
const aiResponse = JSON.parse($input.first().json.choices[0].message.content);
const customer = $input.first().json;

return [{
  json: {
    customerId: customer.customerId || 'CUST-' + Date.now(),
    customerName: customer.customerName,
    email: customer.email,
    knowledgeBase: aiResponse,
    generatedAt: new Date().toISOString(),
    version: '1.0'
  }
}];

parameters.text:
